<main class="page search-page"><div class="page-head"><div><h1>Поиск</h1><p>Люди, каналы и сообщения.</p></div></div><form class="search-large"><input name="q" value="<?=e($q)?>" placeholder="Имя, @ник, канал или текст сообщения" autofocus autocomplete="off"><button class="btn btn-primary">Найти</button></form>
<?php if($q!==''):?>
<section class="search-section"><h2>Люди</h2><div class="people-grid"><?php foreach($userRows as $user):?><article class="person-card"><?=avatar_html($user,'avatar')?><div><a href="<?=e(user_public_url($user['username']))?>"><b><?=e($user['display_name'])?><?=verified_badge($user)?></b></a><small>@<?=e($user['username'])?> · <?=online($user['last_seen_at'])?'в сети':'не в сети'?></small></div><?php if((int)$user['id']!==\Kovcheg\Auth::id()):?><form method="post" action="<?=e(app_url('/chat/direct'))?>"><?=csrf_field()?><input type="hidden" name="user_id" value="<?=(int)$user['id']?>"><button class="btn btn-small">Написать</button></form><?php endif;?></article><?php endforeach;?><?php if(!$userRows):?><p class="muted">Пользователи не найдены.</p><?php endif;?></div></section>
<section class="search-section"><h2>Каналы</h2><div class="search-results"><?php foreach($channelRows as $channel):?><a href="<?=e(chat_public_url($channel,\Kovcheg\Auth::id()))?>"><b># <?=e($channel['title'])?></b><small><?=e(human_time($channel['updated_at']))?></small></a><?php endforeach;?><?php if(!$channelRows):?><p class="muted">Каналы не найдены.</p><?php endif;?></div></section>
<section class="search-section"><h2>Сообщения</h2><div class="search-results"><?php foreach($rows as $r):?><a href="<?=e(message_public_url(['id'=>(int)$r['id'],'chat_id'=>(int)$r['chat_id'],'chat_type'=>(string)($r['type']??'direct')],\Kovcheg\Auth::id()))?>"><b><?=e($r['display_name'])?></b><p><?=e($r['body'])?></p><small><?=e(human_time($r['created_at']))?></small></a><?php endforeach;?><?php if(!$rows):?><p class="muted">Сообщения не найдены.</p><?php endif;?></div></section>
<?php endif;?></main>
